#!/bin/bash`n# lib/network.sh - 网络检测函数库`n`nget_default_interface() {`n    ip route | grep default | awk '{print $5}' | head -1 || echo "eth0"`n}`n`nget_ipv4_addresses() {`n    local eth="${1:-$(get_default_interface)}"`n    ip -4 addr show "$eth" 2>/dev/null | grep -oP '(?<=inet\s)\d+(\.[0-9]+){3}/\d+' || echo ""`n}`n`nget_ipv6_addresses() {`n    local eth="${1:-$(get_default_interface)}"`n    ip -6 addr show "$eth" 2>/dev/null | grep -oP '(?<=inet6\s)[a-f0-9:]+/\d+' || echo ""`n}`n`nis_public_ip() {`n    local ip="$1"`n    local addr="${ip%%/*}"`n    `n    if [[ "$addr" == 10.* ]]; then return 1`n    elif [[ "$addr" == 172.1[6-9].* ]] || [[ "$addr" == 172.2[0-9].* ]] || [[ "$addr" == 172.3[0-1].* ]]; then return 1`n    elif [[ "$addr" == 192.168.* ]]; then return 1`n    elif [[ "$addr" == 127.* ]]; then return 1`n    fi`n    return 0`n}`n`nget_public_ipv4() {`n    local addresses=$(get_ipv4_addresses)`n    for addr in $addresses; do`n        if is_public_ip "$addr"; then`n            echo "$addr"`n            return 0`n        fi`n    done`n    echo ""`n}`n`nget_private_ipv4() {`n    local addresses=$(get_ipv4_addresses)`n    for addr in $addresses; do`n        if ! is_public_ip "$addr"; then`n            echo "$addr"`n            return 0`n        fi`n    done`n    echo ""`n}`n`nget_public_ipv6() {`n    local addresses=$(get_ipv6_addresses)`n    for addr in $addresses; do`n        if [[ "$addr" != fe80:* ]] && [[ "$addr" != fc00:* ]] && [[ "$addr" != fd00:* ]]; then`n            echo "$addr"`n            return 0`n        fi`n    done`n    echo ""`n}`n`nget_gateway_v4() {`n    ip -4 route show default 2>/dev/null | awk '{print $3}' | head -1 || echo ""`n}`n`nget_gateway_v6() {`n    ip -6 route show default 2>/dev/null | awk '{print $3}' | head -1 || echo ""`n}`n`nget_dns_servers() {`n    cat /etc/resolv.conf 2>/dev/null | grep nameserver | awk '{print $2}' | tr '\n' ',' | sed 's/,$//' || echo ""`n}`n`nget_network_type() {`n    local public_v4=$(get_public_ipv4)`n    local private_v4=$(get_private_ipv4)`n    local public_v6=$(get_public_ipv6)`n    local has_gateway=$(get_gateway_v4)`n    `n    if [[ -n "$public_v4" ]] && [[ -n "$public_v6" ]]; then`n        echo "dual"`n    elif [[ -n "$public_v4" ]]; then`n        echo "v4"`n    elif [[ -n "$public_v6" ]]; then`n        echo "v6"`n    elif [[ -n "$private_v4" ]] && [[ -n "$has_gateway" ]]; then`n        echo "nat"`n    else`n        echo "unknown"`n    fi`n}`n`nget_ip_type() {`n    local eth="${1:-$(get_default_interface)}"`n    if ip -4 addr show "$eth" 2>/dev/null | grep -q 'dynamic'; then`n        echo "dhcp"`n    else`n        echo "static"`n    fi`n}`n`nget_network_speed() {`n    local eth="${1:-$(get_default_interface)}"`n    ethtool "$eth" 2>/dev/null | grep "Speed:" | awk '{print $2}' || echo "unknown"`n}`n`nget_mtu() {`n    local eth="${1:-$(get_default_interface)}"`n    cat "/sys/class/net/$eth/mtu" 2>/dev/null || echo "1500"`n}`n`ndetect_network() {`n    local eth=$(get_default_interface)`n    cat << EOF`nNET_INTERFACE=$eth`nNET_TYPE=$(get_network_type)`nIP_TYPE=$(get_ip_type $eth)`nPUBLIC_V4=$(get_public_ipv4)`nPRIVATE_V4=$(get_private_ipv4)`nPUBLIC_V6=$(get_public_ipv6)`nGATEWAY_V4=$(get_gateway_v4)`nGATEWAY_V6=$(get_gateway_v6)`nDNS_SERVERS=$(get_dns_servers)`nNET_SPEED=$(get_network_speed $eth)`nMTU=$(get_mtu $eth)`nEOF`n}`n